def range_summary(nums):
    if not nums:
        return ''

    distinct_nums = sorted(set(nums))
    result = []

    for i in range(len(distinct_nums) - 1):
        diff = distinct_nums[i + 1] - distinct_nums[i]
        if diff == 1:
            continue
        elif diff > 1:
            last_range = f'{distinct_nums[i]}-{distinct_nums[i+1]-1}'
            result.append(last_range)

    if distinct_nums[0] != distinct_nums[-1]:
        single_num = str(distinct_nums[0])
        result.insert(0, single_num)

    for num in distinct_nums[1:-1]:
        range_str = f'{num}-{num-1}'
        result.insert(len(result), range_str)

    return ','.join(result)
